mapper.insert:
		/*
             SQL ID : LessonTimeDAO.insert
             설  명 : 교시 등록
         */
		INSERT INTO TB_LMS_SBJCT_LCTR_CLASTM (
			  SBJCT_LCTR_CLASTM_ID
			, LCTR_SCHDL_ID
			, SBJCT_ID
			, LCTR_CLASTMNM
			, LCTR_CLASTM_SEQ
			, LCTR_MTHD
			, RGTR_ID
			, FRST_INQ_DTTM
		) VALUES (
			  #{lessonTimeId}
			, #{lessonScheduleId}
			, #{crsCreCd}
			, #{lessonTimeNm}
			, #{lessonTimeOrder}
			, #{stdyMethod}
			, #{rgtrId}
			, FN_DTTM()
		)

mapper.update:
		/*
             SQL ID : LessonTimeDAO.update
             설  명 : 교시 수정
         */
		UPDATE TB_LMS_SBJCT_LCTR_CLASTM
		SET
			  MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()

			, LCTR_CLASTMNM = #{lessonTimeNm}


			, LCTR_CLASTM_SEQ = #{lessonTimeOrder}


			, LCTR_MTHD = #{stdyMethod}

		WHERE SBJCT_LCTR_CLASTM_ID = #{lessonTimeId}

mapper.delete:
		/*
             SQL ID : LessonTimeDAO.delete
             설  명 : 교시 삭제
         */
		DELETE FROM TB_LMS_SBJCT_LCTR_CLASTM
		WHERE SBJCT_LCTR_CLASTM_ID = #{lessonTimeId}

mapper.select:
/* SQL ID : LessonTimeDAO.list 설 명 : 교시 목록 조회 */ SELECT A.SBJCT_LCTR_CLASTM_ID , A.LCTR_SCHDL_ID , A.SBJCT_ID , A.LCTR_CLASTMNM , A.LCTR_CLASTM_SEQ , A.LCTR_MTHD , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_SBJCT_LCTR_CLASTM A
AND A.LCTR_SCHDL_ID = #{lessonScheduleId}
AND A.SBJCT_ID = #{crsCreCd}
ORDER BY LCTR_CLASTM_SEQ

mapper.insert:
        /*
             SQL ID : LessonTimeDAO.insertLessonTimeListForTrans
             설  명 : 교시목록 저장(선수강과목 이관용)
        */
		INSERT IGNORE INTO TB_LMS_SBJCT_LCTR_CLASTM (
			  SBJCT_LCTR_CLASTM_ID
			, LCTR_SCHDL_ID
			, SBJCT_ID
			, LCTR_CLASTMNM
			, LCTR_CLASTM_SEQ
			, LCTR_MTHD
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		) VALUES

		(
			  #{item.lessonTimeId}
			, #{item.lessonScheduleId}
			, #{item.crsCreCd}
			, #{item.lessonTimeNm}
			, #{item.lessonTimeOrder}
			, #{item.stdyMethod}
			, #{item.rgtrId}
			, #{item.regDttm}
			, #{item.mdfrId}
			, #{item.modDttm}
	    )
